# Python
age = 12
if age < 13:
    print('You are young!')
else:
    print('You are a teenager!')

# Python
class Dog:
    def __init__(self, name):
        self.name = name

    def bark(self):
        return f'{self.name} says Woof!'

my_dog = Dog('Buddy')
print(my_dog.bark())

# Python
class Animal:
    def __init__(self, name):
        self.name = name
    def sound(self):
        pass

class Dog(Animal):
    def sound(self):
        return f'{self.name} barks!'

dog = Dog('Buddy')
print(dog.sound())

# Python
class Dog:
    def sound(self):
        return 'Woof!'

class Cat:
    def sound(self):
        return 'Meow!'

for animal in [Dog(), Cat()]:
    print(animal.sound())  # Different output!

# Python - Singleton Pattern
class Database:
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance
